diff --git a/test/conformance/serial/ptp.go b/test/conformance/serial/ptp.go
index a528935..fd63803 100644
--- a/test/conformance/serial/ptp.go
+++ b/test/conformance/serial/ptp.go
@@ -2118,7 +2118,13 @@ var _ = Describe("["+strings.ToLower(DesiredMode.String())+"-serial]", Serial, f
 				})

 				By("Checking initial clock class is Locked (6)")
-				checkClockClassState(fullConfig, strconv.Itoa(int(fbprotocol.ClockClass6)), pkg.TimeoutIn5Minutes)
+				if ptphelper.IsPTPOperatorVersionAtLeast("4.18") {
+					checkClockClassState(fullConfig, strconv.Itoa(int(fbprotocol.ClockClass6)), pkg.TimeoutIn5Minutes)
+				} else {
+					configFile, err := ptptesthelper.DiscoverPrimaryPtp4lConfig(fullConfig)
+					Expect(err).NotTo(HaveOccurred())
+					ptptesthelper.VerifyClockClassViaPMC(fullConfig, configFile, int(fbprotocol.ClockClass6))
+				}

 				By("Setting all slave interfaces down")
 				skippedInterfacesStr, isSet := os.LookupEnv("SKIP_INTERFACES")
@@ -2151,7 +2157,10 @@ var _ = Describe("["+strings.ToLower(DesiredMode.String())+"-serial]", Serial, f

 				By("Checking clock class has degraded away from Locked (6)")
 				Eventually(func() bool {
-					return !checkClockClassStateReturnBool(fullConfig, strconv.Itoa(int(fbprotocol.ClockClass6)))
+					if ptphelper.IsPTPOperatorVersionAtLeast("4.18") {
+						return !checkClockClassStateReturnBool(fullConfig, strconv.Itoa(int(fbprotocol.ClockClass6)))
+					}
+					return ptptesthelper.CheckClockClassDegradedViaPMCReturnBool(fullConfig, int(fbprotocol.ClockClass6))
 				}, 5*time.Minute, 10*time.Second).Should(BeTrue(),
 					"expected clock class to degrade from Locked (6) after upstream link loss")

@@ -2165,7 +2174,13 @@ var _ = Describe("["+strings.ToLower(DesiredMode.String())+"-serial]", Serial, f
 				}, 5*time.Minute, 10*time.Second).Should(BeNil())

 				By("Checking clock class recovers to Locked (6)")
-				waitForClockClass(fullConfig, strconv.Itoa(int(fbprotocol.ClockClass6)))
+				if ptphelper.IsPTPOperatorVersionAtLeast("4.18") {
+					waitForClockClass(fullConfig, strconv.Itoa(int(fbprotocol.ClockClass6)))
+				} else {
+					configFile, err := ptptesthelper.DiscoverPrimaryPtp4lConfig(fullConfig)
+					Expect(err).NotTo(HaveOccurred())
+					ptptesthelper.VerifyClockClassViaPMC(fullConfig, configFile, int(fbprotocol.ClockClass6))
+				}

 				logrus.Info("Successfully verified T-BC clock class recovery after upstream link outage")
 			})
diff --git a/test/pkg/ptptesthelper/ptptesthelper.go b/test/pkg/ptptesthelper/ptptesthelper.go
index a0d2818..d257d73 100644
--- a/test/pkg/ptptesthelper/ptptesthelper.go
+++ b/test/pkg/ptptesthelper/ptptesthelper.go
@@ -756,19 +756,55 @@ func verifyNodeClockClassWithMetrics(fullConfig testconfig.TestConfig, expectedC
 }

 // VerifyNICClockClass checks the expected clock class for a NIC via PMC and metrics.
-// isDualNIC controls the metric check on OCP < 4.18:
-//   - On OCP >= 4.18: always verifies via per-config metric (config label available).
-//   - On OCP < 4.18, single NIC: verifies via node-level metric (no config label).
-//   - On OCP < 4.18, dual NIC: metrics skipped (single metric can't distinguish NICs).
+// isDualNIC is retained for call-site clarity but unused on OCP < 4.18.
+//   - On OCP >= 4.18: verifies via PMC + per-config metric (config label available).
+//   - On OCP < 4.18: verifies via PMC only. The node-level openshift_ptp_clock_class
+//     metric (no config label) is not updated for BC on 4.14–4.17 even when ptp4l
+//     changes class; per-config metrics are unavailable until 4.18.
 func VerifyNICClockClass(fullConfig testconfig.TestConfig, nic NICInfo, expectedClass int, isDualNIC bool) {
 	VerifyClockClassViaPMC(fullConfig, nic.ConfigFile, expectedClass)
 	if ptphelper.IsPTPOperatorVersionAtLeast("4.18") {
 		VerifyPerConfigClockClassWithMetrics(fullConfig, nic.ConfigName, expectedClass)
-	} else if !isDualNIC {
-		verifyNodeClockClassWithMetrics(fullConfig, expectedClass)
 	}
 }

