+				// BC configs default to gmCapable=0; ptp4l won't change clockClass on
+				// sync loss without gmCapable=1. Enable it for the duration of this test.
+				var gmCapableRestore []func()
+				primaryCfg := (*ptpv1.PtpConfig)(*fullConfig.DiscoveredClockUnderTestPtpConfig)
+				origPrimary := ptptesthelper.EnableGMCapableInPlace(primaryCfg.Name)
+				gmCapableRestore = append(gmCapableRestore, func() {
+					ptptesthelper.RestorePtp4lConf(primaryCfg.Name, origPrimary)
+				})
+				if fullConfig.PtpModeDiscovered == testconfig.DualNICBoundaryClock ||
+					fullConfig.PtpModeDiscovered == testconfig.DualNICBoundaryClockHA {
+					secondaryCfg := (*ptpv1.PtpConfig)(*fullConfig.DiscoveredClockUnderTestSecondaryPtpConfig)
+					origSecondary := ptptesthelper.EnableGMCapableInPlace(secondaryCfg.Name)
+					gmCapableRestore = append(gmCapableRestore, func() {
+						ptptesthelper.RestorePtp4lConf(secondaryCfg.Name, origSecondary)
+					})
+				}
+				DeferCleanup(func() {
+					for _, restore := range gmCapableRestore {
+						restore()
+					}
+				})
+				nic1 := ptptesthelper.DiscoverNICInfo(primaryCfg, slavePodNodeName, "NIC-1")
+				ptptesthelper.WaitForConfigContent(fullConfig, nic1.ConfigFile, "gmCapable 1")
+				if fullConfig.PtpModeDiscovered == testconfig.DualNICBoundaryClock ||
